Greedy insertion with parallel evaluation of all feasible assign positions using incremental cost calculation and fallback to empty assign creation when needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for orderIdx := range oris {
        bestAssignIdx := -1
        bestCostIncrease := 1e308
        ori := oris[orderIdx]
        des := dess[orderIdx]
        shipID := total_ship + orderIdx

        for i := 0; i < MAXASSIGNS; i++ {
            if i >= dispatch.AssignsLen && i != dispatch.AssignsLen {
                continue
            }
            originalCost := dispatch.Assigns[i].Cost
            added := false
            if i >= dispatch.AssignsLen {
                added = dispatch.Assigns[i].AddShip(shipID, ori, des)
            } else {
                added = dispatch.Assigns[i].AddShip(shipID, ori, des)
            }
            if added {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costIncrease := dispatch.Assigns[i].Cost - originalCost
                    if costIncrease < bestCostIncrease {
                        bestCostIncrease = costIncrease
                        bestAssignIdx = i
                    }
                }
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].GenRoute()
            }
        }

        if bestAssignIdx >= 0 {
            targetIdx := bestAssignIdx
            if targetIdx >= dispatch.AssignsLen {
                dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[targetIdx].GenRoute()
                dispatch.AssignsLen++
            } else {
                dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[targetIdx].GenRoute()
            }
        } else {
            fallbackIdx := dispatch.AssignsLen
            if fallbackIdx < MAXASSIGNS {
                dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[fallbackIdx].GenRoute()
                if dispatch.Assigns[fallbackIdx].Cost >= 0 {
                    dispatch.AssignsLen++
                } else {
                    dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
                    dispatch.Assigns[fallbackIdx].GenRoute()
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

